1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	};
8	
9	type Item = { type: string };
10	type QuoteStep = { op: "quote"; items: Item[] };
11	type Step = QuoteStep;
12	type Scenario = { customer: unknown; steps: Step[] };
13	type QuoteResult = { premium: number };
14	type StepResult = QuoteResult;
15	
16	const basePremiumForItem = (item: Item): number =>
17	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
18	
19	const sumItemBasePremiums = (items: Item[]): number =>
20	  items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
21	
22	const quote = (step: QuoteStep): QuoteResult => ({
23	  premium: sumItemBasePremiums(step.items) + PROCESSING_FEE,
24	});
25	
26	export const processScenario = (input: Scenario): { results: StepResult[] } => {
27	  const results = input.steps.map((step) => quote(step));
28	  return { results };
29	};
